('chunk_1c7da71cb6d1d6869b','file_8378b145fc1fad06fd','physics.md','Subject Overview','Physics at IISH is taught within the **MYP Sciences** subject group. Sciences in the MYP encourages students to investigate the physical world, develop scientific inquiry skills, and reflect on how science shapes and is shaped by society. Grade 7 sits in **MYP Year 2**, building the conceptual and practical foundations for later diploma-level study.','{"subject":2,"overview":1,"physics":1,"iish":1,"taught":1,"within":1,"the":4,"myp":3,"sciences":2,"group":1,"encourages":1,"students":1,"investigate":1,"physical":1,"world":1,"develop":1,"scientific":1,"inquiry":1,"skills":1,"and":3,"reflect":1,"how":1,"science":1,"shapes":1,"shaped":1,"society":1,"grade":1,"sits":1,"year":1,"building":1,"conceptual":1,"practical":1,"foundations":1,"for":1,"later":1,"diploma":1,"level":1,"study":1}'::jsonb),
('chunk_639bcdc5850675feba','file_8378b145fc1fad06fd','physics.md','The Four Sciences Assessment Criteria','Every unit is assessed against four equally weighted criteria, each scored out of 8:

| Criterion | Title | What it assesses |
|-----------|-------|------------------|
| **A** | Knowing and understanding | Recalling scientific knowledge; applying it to solve problems in familiar and unfamiliar situations; analysing and evaluating information to make judgements. |
| **B** | Inquiring and designing | Stating problems/questions; formulating testable hypotheses; identifying variables; designing a fair, logical, safe method. |
| **C** | Processing and evaluating | Presenting and organising data; interpreting data and drawing conclusions; evaluating validity of the method and improving the investigation. |
| **D** | Reflecting on the impacts of science | Explaining how science is applied to a problem/issue; discussing implications on society and the environment; evaluating scientific communication. |','{"the":5,"four":2,"sciences":1,"assessment":1,"criteria":2,"every":1,"unit":1,"assessed":1,"against":1,"equally":1,"weighted":1,"each":1,"scored":1,"out":1,"criterion":1,"title":1,"what":1,"assesses":1,"knowing":1,"and":9,"understanding":1,"recalling":1,"scientific":2,"knowledge":1,"applying":1,"solve":1,"problems":2,"familiar":1,"unfamiliar":1,"situations":1,"analysing":1,"evaluating":4,"information":1,"make":1,"judgements":1,"inquiring":1,"designing":2,"stating":1,"questions":1,"formulating":1,"testable":1,"hypotheses":1,"identifying":1,"variables":1,"fair":1,"logical":1,"safe":1,"method":2,"processing":1,"presenting":1,"organising":1,"data":2,"interpreting":1,"drawing":1,"conclusions":1,"validity":1,"improving":1,"investigation":1,"reflecting":1,"impacts":1,"science":2,"explaining":1,"how":1,"applied":1,"problem":1,"issue":1,"discussing":1,"implications":1,"society":1,"environment":1,"communication":1}'::jsonb),
